proof fn phi_2_lemma_write_seq_external_body(pt: PTMem, writes: Seq<(usize, usize)>)
    ensures
        pt.write_seq(writes).pml4 == pt.pml4,
        pt.mem.dom().subset_of(pt.write_seq(writes).mem.dom()),
{
    pt.lemma_write_seq(writes);
}

proof fn phi_3_write_seq_push_depends_on_two_external_body(pt: PTMem, addr: usize, value: usize)
    ensures
        pt.write_seq(Seq::<(usize, usize)>::empty().push((addr, value)))
            == (PTMem {
                pml4: pt.pml4,
                mem: pt.write_seq(Seq::<(usize, usize)>::empty()).mem.insert(addr, value),
            }),
{
    pt.lemma_write_seq_push(Seq::<(usize, usize)>::empty(), addr, value);
}

